import bisect
class Solution:
    def totalScore(self, hp: int, damage, requirement) -> int:
        n = len(damage)
        D = [0] * (n + 1)
        for i in range(n):
            D[i + 1] = D[i] + damage[i]
        total = 0
        for i in range(n):
            R = requirement[i] + D[i + 1] - hp
            idx = bisect.bisect_left(D, R)
            cnt = (i + 1) - idx
            if cnt > 0:
                total += cnt
        return total

