var totalScore = function(hp, damage, requirement) {
    const n = damage.length;
    const D = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) D[i + 1] = D[i] + damage[i];
    function bisectLeft(target) {
        let lo = 0, hi = D.length;
        while (lo < hi) {
            const mid = (lo + hi) >> 1;
            if (D[mid] < target) lo = mid + 1; else hi = mid;
        }
        return lo;
    }
    let total = 0;
    for (let i = 0; i < n; i++) {
        const R = requirement[i] + D[i + 1] - hp;
        const idx = bisectLeft(R);
        const cnt = (i + 1) - idx;
        if (cnt > 0) total += cnt;
    }
    return total;
};
